async #getWorkerMessagingChannel ({ id, application, worker }, context) {
  if (this.#channelCreationHook?.(id, application) === false) {
    throw new MessagingError(
      application,
      `Communication channels are disabled between applications "${id}" and "${application}".`
    )
  }

  const target = await this.#getWorkerByIdOrNext(application, worker, true, true)

  const { port1, port2 } = new MessageChannel()

  // Send the first port to the target
  const response = await executeWithTimeout(
    sendViaITC(target, 'saveMessagingChannel', port1, [port1]),
    this.#config.messagingTimeout
  )

  if (response === kTimeout) {
    throw new MessagingError(application, 'Timeout while establishing a communication channel.')
  }

  context.transferList = [port2]
  this.emitAndNotify('application:worker:messagingChannel', { application, worker })
  return port2
}

function RequestContextPlugin(fastify: FastifyInstance, _options, next) {
  fastify.addHook(
    'onRequest',
    (request: FastifyRequest, reply: FastifyReply, hookIsDone) => {
      let requestId: string | undefined;
      if (Array.isArray(request.headers[REQUEST_ID_HEADER])) {
        const [firstRequestId] = request.headers[REQUEST_ID_HEADER];
        requestId = firstRequestId;
      } else {
        requestId = request.headers[REQUEST_ID_HEADER];
      }

      if (!requestId) {
        requestId = randomUUID();
        request.headers[REQUEST_ID_HEADER] = requestId;
      }

      // // reply.header[REQUEST_ID_HEADER] = requestId;

      const currentContext = context().getStore();

      if (currentContext) {
        currentContext.requestId = requestId;
        hookIsDone();
        return;
      }

      context().run({ requestId }, hookIsDone);
    }
  );
  next();
}

private async runWithTimeout<T>(
  operation: (context: TContext) => Promise<T>,
  context: TContext,
  timeout: number,
  stageName: string
): Promise<T> {
  return new Promise((resolve, reject) => {
    const timeoutId = setTimeout(() => {
      reject(new Error(`Stage '${stageName}' timeout after ${timeout}ms`) as OrchestratorError);
    }, timeout);

    operation(context)
      .then((result) => {
        clearTimeout(timeoutId);
        resolve(result);
      })
      .catch((error) => {
        clearTimeout(timeoutId);
        reject(error);
      });
  });
}

