export async function startServer(
  server: FastifyInstance,
  port: number = parseInt(process.env.PORT || '3000') || 3000
) {
  await server.ready().then(
    () => {
      server.log.debug('Starting server')
    },
    error => {
      if (error) {
        throw error
      }
    }
  )
  return await new Promise(resolve => {
    server.listen({ port, host: '0.0.0.0' }, (error, address) => {
      if (error) {
        server.log.fatal({ msg: `Application startup error`, error, address })
        process.exit(1)
      } else {
        resolve(server)
      }
    })
  })
}

function encapsulateTwoParam (func, that) {
  return _encapsulateTwoParam.bind(that)
  function _encapsulateTwoParam (context, cb) {
    let res
    if (func.length === 0) {
      res = func()
      if (res?.then) {
        res.then(function () {
          process.nextTick(cb)
        }, cb)
      } else {
        process.nextTick(cb)
      }
    } else if (func.length === 1) {
      res = func(this)

      if (res?.then) {
        res.then(function () {
          process.nextTick(cb)
        }, cb)
      } else {
        process.nextTick(cb)
      }
    } else {
      func(this, cb)
    }
  }
}
